'use client';

import { useEffect, useMemo, useState } from 'react';
import { usePathname, useRouter } from 'next/navigation';
import { Check, ChevronDown, LayoutGrid } from 'lucide-react';
import { ChartContainer } from './ChartContainer';
import { Button } from '@/components/ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { cn } from '@/lib/utils';

type WorkspaceLayout = 'single' | 'two-up' | 'quad' | 'nine' | 'hero-bottom';

interface MultiChartWorkspaceProps {
  symbol: string;
  initialLayout?: WorkspaceLayout;
}

interface LayoutOption {
  id: WorkspaceLayout;
  label: string;
  description: string;
  panelCount: number;
  gridClassName: string;
  cells: Array<{ key: string; className?: string }>;
}

const STORAGE_KEY = 'artha.chart.workspaceLayout';

const LAYOUT_OPTIONS: LayoutOption[] = [
  {
    id: 'single',
    label: 'Single chart',
    description: 'One focused chart view',
    panelCount: 1,
    gridClassName: 'grid-cols-1 grid-rows-1',
    cells: [{ key: 'single' }],
  },
  {
    id: 'two-up',
    label: '2 charts',
    description: 'Side-by-side comparison',
    panelCount: 2,
    gridClassName: 'grid-cols-1 md:grid-cols-2',
    cells: [{ key: 'left' }, { key: 'right' }],
  },
  {
    id: 'quad',
    label: '4 charts',
    description: 'Balanced 2 × 2 grid',
    panelCount: 4,
    gridClassName: 'grid-cols-1 md:grid-cols-2 md:grid-rows-2',
    cells: [{ key: 'q1' }, { key: 'q2' }, { key: 'q3' }, { key: 'q4' }],
  },
  {
    id: 'nine',
    label: '9 charts',
    description: 'Dense market monitor',
    panelCount: 9,
    gridClassName: 'grid-cols-1 md:grid-cols-2 xl:grid-cols-3 xl:grid-rows-3',
    cells: [
      { key: 'n1' }, { key: 'n2' }, { key: 'n3' },
      { key: 'n4' }, { key: 'n5' }, { key: 'n6' },
      { key: 'n7' }, { key: 'n8' }, { key: 'n9' },
    ],
  },
  {
    id: 'hero-bottom',
    label: '1 big + 2 small',
    description: 'Primary chart with two secondary panels',
    panelCount: 3,
    gridClassName: 'grid-cols-1 md:grid-cols-2 md:grid-rows-[minmax(0,1.6fr)_minmax(0,1fr)]',
    cells: [
      { key: 'hero', className: 'md:col-span-2' },
      { key: 'bottom-left' },
      { key: 'bottom-right' },
    ],
  },
];

function getLayout(layout: WorkspaceLayout): LayoutOption {
  return LAYOUT_OPTIONS.find((option) => option.id === layout) ?? LAYOUT_OPTIONS[0];
}

function LayoutPreview({ layoutId }: { layoutId: WorkspaceLayout }) {
  const layout = getLayout(layoutId);
  const previewClassName = {
    single: 'grid-cols-1 grid-rows-1',
    'two-up': 'grid-cols-2 grid-rows-1',
    quad: 'grid-cols-2 grid-rows-2',
    nine: 'grid-cols-3 grid-rows-3',
    'hero-bottom': 'grid-cols-2 grid-rows-[1.5fr_1fr]',
  }[layoutId];

  return (
    <div className={cn('grid h-8 w-10 gap-1 rounded-md border border-[var(--border)] bg-[var(--bg-app)] p-1', previewClassName)}>
      {layout.cells.map((cell) => (
        <span
          key={cell.key}
          className={cn(
            'rounded-[3px] border border-[var(--border)] bg-[var(--bg-card)]',
            layoutId === 'hero-bottom' && cell.key === 'hero' ? 'col-span-2' : null
          )}
        />
      ))}
    </div>
  );
}

export function MultiChartWorkspace({ symbol, initialLayout = 'single' }: MultiChartWorkspaceProps) {
  const router = useRouter();
  const pathname = usePathname();
  const [layout, setLayout] = useState<WorkspaceLayout>(initialLayout);

  useEffect(() => {
    if (initialLayout !== 'single') return;
    const saved = globalThis.window?.localStorage.getItem(STORAGE_KEY) as WorkspaceLayout | null;
    if (saved && LAYOUT_OPTIONS.some((option) => option.id === saved)) {
      setLayout(saved);
    }
  }, [initialLayout]);

  useEffect(() => {
    globalThis.window?.localStorage.setItem(STORAGE_KEY, layout);
    const query = layout === 'single' ? '' : `?layout=${layout}`;
    router.replace(`${pathname}${query}`, { scroll: false });
  }, [layout, pathname, router]);

  const activeLayout = useMemo(() => getLayout(layout), [layout]);

  return (
    <div className="flex h-screen min-h-screen flex-col overflow-hidden bg-[var(--bg-app)] text-[var(--text-primary)]">
      <div className="flex items-center justify-between gap-3 border-b border-[var(--border)] bg-[var(--bg-card)] px-4 py-3">
        <div className="min-w-0">
          <div className="flex items-center gap-2">
            <span className="text-sm font-semibold tracking-tight">{symbol}</span>
            <span className="rounded-full bg-[var(--brand-tint)] px-2 py-0.5 text-[11px] font-medium text-[var(--brand-primary)]">
              {activeLayout.panelCount} {activeLayout.panelCount === 1 ? 'panel' : 'panels'}
            </span>
          </div>
          <p className="mt-0.5 text-xs text-[var(--text-secondary)]">
            Switch chart layouts without leaving the fullscreen workspace.
          </p>
        </div>

        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="outline" size="sm" className="gap-2">
              <LayoutGrid size={15} />
              <span>{activeLayout.label}</span>
              <ChevronDown size={14} className="text-[var(--text-muted)]" />
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end" className="w-80">
            <DropdownMenuLabel>Chart layout</DropdownMenuLabel>
            <DropdownMenuSeparator />
            {LAYOUT_OPTIONS.map((option) => (
              <DropdownMenuItem
                key={option.id}
                onClick={() => setLayout(option.id)}
                className="items-start gap-3 rounded-md px-3 py-2"
              >
                <LayoutPreview layoutId={option.id} />
                <div className="min-w-0 flex-1">
                  <div className="flex items-center justify-between gap-2">
                    <span className="text-sm font-medium text-[var(--text-primary)]">{option.label}</span>
                    {layout === option.id ? <Check size={14} className="text-[var(--brand-primary)]" /> : null}
                  </div>
                  <p className="mt-0.5 text-xs text-[var(--text-secondary)]">{option.description}</p>
                </div>
              </DropdownMenuItem>
            ))}
          </DropdownMenuContent>
        </DropdownMenu>
      </div>

      <div className="min-h-0 flex-1 overflow-hidden p-3">
        {layout === 'single' ? (
          <div className="h-full overflow-hidden rounded-2xl border border-[var(--border)] bg-[var(--bg-card)] shadow-sm">
            <ChartContainer symbol={symbol} workspaceMode />
          </div>
        ) : (
          <div className={cn('grid h-full min-h-0 gap-3', activeLayout.gridClassName)}>
            {activeLayout.cells.map((cell, index) => (
              <div
                key={cell.key}
                className={cn(
                  'min-h-0 overflow-hidden rounded-2xl border border-[var(--border)] bg-[var(--bg-card)] shadow-sm',
                  cell.className
                )}
              >
                <iframe
                  title={`${symbol} chart panel ${index + 1}`}
                  src={`/stocks/${encodeURIComponent(symbol)}/chart?embed=1&panel=${index + 1}`}
                  className="h-full w-full border-0 bg-transparent"
                />
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
